import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { Observable } from "rxjs";
import { AlertService } from "./alert.service";
import { EnvService } from "./env.service";
import {
  CashOutCheckClientResponse,
  CashOutCheckOtpRequest,
  CashOutCheckOtpResponse,
  CashOutDisburseLoanRequest,
  CashOutDisburseLoanResponse,
} from "src/app/views/Models/CashOut/CheckClient";

@Injectable({
  providedIn: "root",
})
export class CashOutService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService
  ) {}

  checkNationId = (
    nationalId: string
  ): Observable<CashOutCheckClientResponse> => {
    try {
      return this.http.get<CashOutCheckClientResponse>(
        this.env.API_URL +
          `api/CashOut/NationIdChecking?nationalId=${nationalId}`
      );
    } catch (error) {
      console.error("Error getHierarchyDashboardSummary:", error);
      throw error;
    }
  };
  checkOtp = (
    request: CashOutCheckOtpRequest
  ): Observable<CashOutCheckOtpResponse> => {
    try {
      return this.http.post<CashOutCheckOtpResponse>(
        this.env.API_URL + `api/CashOut/CheckOtp`,
        {
          otp: request.otp.toString(),
          nation_id: request.nationalId.toString(),
          preshared_key: null,
          ref_no: request.referenceNumber,
        }
      );
    } catch (error) {
      console.error("Error getHierarchyDashboardSummary:", error);
      throw error;
    }
  };
  disburseLoan = (
    request: CashOutDisburseLoanRequest
  ): Observable<CashOutDisburseLoanResponse> => {
    try {
      return this.http.post<CashOutDisburseLoanResponse>(
        this.env.API_URL + `api/CashOut/DisburseLoan`,
        {
          nation_id: request.nationalId,
          ref_no: request.referenceNumber,
        }
      );
    } catch (error) {
      console.error("Error getHierarchyDashboardSummary:", error);
      throw error;
    }
  };
}
