import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormControl, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { CashOutService } from "src/app/core/services/cash-out.service";
import {
  nationalIdValidator,
  otpVerificationValidator,
} from "src/app/core/validators/custom-validators";
import {
  CashOutCheckClientRequest,
  CashOutCheckClientResponse,
  CashOutCheckOtpRequest,
  CashOutCheckOtpResponse,
  CashOutDisburseLoanRequest,
  CashOutDisburseLoanResponse,
} from "src/app/views/Models/CashOut/CheckClient";

interface FormsState {
  identificationForm: IdentificationForm;
  smsForm: SmsForm;
  clientInformationForm: ClientInformationForm;
  showLoader: boolean;
}
interface IdentificationForm {
  formGroup: FormGroup;
  formControlsNames: {
    nationalId: string;
  };
  visible: boolean;
  checkIfInputsValid: boolean;
}
interface SmsForm {
  formGroup: FormGroup;
  formControlsNames: {
    otpInput: string;
  };
  visible: boolean;
  checkIfInputsValid: boolean;
  timeOut: {
    howManySecondsForSmsTimeout: number;
    disableResendSmsButton: boolean;
    timeRemaining: number;
    intervalId: NodeJS.Timeout;
  };
}
interface ClientInformationForm {
  visible: boolean;
}
interface DataBaseRequestsAndResponses {
  checkClient: {
    request: CashOutCheckClientRequest;
    response: CashOutCheckClientResponse;
  };
  checkOtp: {
    request: CashOutCheckOtpRequest;
    response: CashOutCheckOtpResponse;
  };
  disburseLoan: {
    request: CashOutDisburseLoanRequest;
    response: CashOutDisburseLoanResponse;
  };
}

@Component({
  selector: "app-expenses",
  templateUrl: "./expenses.page.html",
  styleUrls: ["./expenses.page.scss"],
})
export class ExpensesPage implements OnInit {
  //#region Objects
  formsState: FormsState = {
    identificationForm: null,
    smsForm: null,
    clientInformationForm: null,
    showLoader: false,
  };
  DataBaseRequestsAndResponses: DataBaseRequestsAndResponses = {
    checkClient: {
      request: { nationalId: null },
      response: {
        result: { message: null, ref_no: null, response_status: null },
      },
    },
    checkOtp: {
      request: { nationalId: null, otp: null, referenceNumber: null },
      response: {
        response_status: null,
        result: {
          client_name: null,
          disbursement_amount: null,
          message: null,
          nation_id: null,
        },
      },
    },
    disburseLoan: {
      request: {
        nationalId: null,
        referenceNumber: null,
      },
      response: { message: null, response_status: null },
    },
  };
  //#endregion

  constructor(
    private formBuilder: FormBuilder,
    private alertService: AlertService,
    private cashOutService: CashOutService
  ) {}
  ngOnInit() {
    this.initializeForms();
  }

  private initializeForms(): void {
    this.formsState.identificationForm = {
      checkIfInputsValid: false,
      visible: true,
      formGroup: this.formBuilder.group({
        nationalId: new FormControl(null, [
          nationalIdValidator({ required: true }),
        ]),
      }),
      formControlsNames: { nationalId: "nationalId" },
    };
    this.formsState.smsForm = {
      checkIfInputsValid: false,
      visible: false,
      formGroup: this.formBuilder.group({
        otpInput: new FormControl(null, [
          otpVerificationValidator({ required: true }),
        ]),
      }),
      formControlsNames: { otpInput: "otpInput" },
      timeOut: {
        howManySecondsForSmsTimeout: 5,
        disableResendSmsButton: true,
        timeRemaining: null,
        intervalId: null,
      },
    };
    this.formsState.clientInformationForm = {
      visible: false,
    };
    this.formsState.showLoader = false;
  }

  //#region Buttons
  async submittingIdentificationForm() {
    if (!this.formsState.identificationForm.formGroup.valid)
      return (this.formsState.identificationForm.checkIfInputsValid = true);

    try {
      this.formsState.showLoader = true;
      await this.verifyNationalId();
    } catch (error) {
      return this.alertService.showAlertError("لا توجد بيانات", false);
    } finally {
      this.formsState.showLoader = false;
    }
    this.formsState.smsForm.formGroup.patchValue({ otpInput: null });
    this.formsState.identificationForm.visible = false;
    this.formsState.smsForm.visible = true;
    this.startSmsTimeout(
      this.formsState.smsForm.timeOut.howManySecondsForSmsTimeout
    );
  }
  async submittingSmsForm() {
    if (!this.formsState.smsForm.formGroup.valid)
      return (this.formsState.smsForm.checkIfInputsValid = true);

    try {
      this.formsState.showLoader = true;
      await this.verifyOtp();
    } catch (error) {
      return this.alertService.showAlertError(error || "حدث خطا", false);
    } finally {
      this.formsState.showLoader = false;
    }
    this.formsState.smsForm.visible = false;
    this.formsState.clientInformationForm.visible = true;
  }
  async submittingClientInformationForm() {
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.formsState.showLoader = true;
      await this.verifyDisburseLoan();
    } catch (error) {
      return this.alertService.showAlertError(error, false);
    } finally {
      this.formsState.showLoader = false;
    }
    this.alertService.showAlertConfirm("تم الصرف بنجاح", true);
  }
  //#endregion

  reSendingOtp = async () => {
    try {
      this.formsState.showLoader = true;
      await this.verifyNationalId();
    } catch (error) {
      return this.alertService.showAlertError(error, false);
    } finally {
      this.formsState.showLoader = false;
    }
    this.startSmsTimeout(
      this.formsState.smsForm.timeOut.howManySecondsForSmsTimeout
    );
  };
  startSmsTimeout = (durationInSeconds: number): void => {
    this.formsState.smsForm.timeOut.disableResendSmsButton = true;
    this.formsState.smsForm.timeOut.timeRemaining = durationInSeconds;

    this.formsState.smsForm.timeOut.intervalId = setInterval(() => {
      if (this.formsState.smsForm.timeOut.timeRemaining <= 0) {
        this.formsState.smsForm.timeOut.timeRemaining = null;
        this.formsState.smsForm.timeOut.disableResendSmsButton = false;
        clearInterval(this.formsState.smsForm.timeOut.intervalId);
      } else {
        this.formsState.smsForm.timeOut.timeRemaining -= 1;
      }
    }, 1000);
  };
  backButton = (): void => {
    // sms ==> identification
    if (this.formsState.smsForm.visible) {
      this.formsState.smsForm.visible = false;
      clearInterval(this.formsState.smsForm.timeOut.intervalId);
      this.clearIdentificationFormValues();
      this.formsState.smsForm.checkIfInputsValid = false;
      this.formsState.identificationForm.visible = true;
    }
    // client ==> identification
    if (this.formsState.clientInformationForm.visible) {
      this.clearIdentificationFormValues();
      this.formsState.clientInformationForm.visible = false;
      this.formsState.identificationForm.visible = true;
    }
  };
  keyboardEvent(event: KeyboardEvent): void {
    if (event.key == "Enter") {
      if (this.formsState.identificationForm.visible)
        this.submittingIdentificationForm();
      if (this.formsState.smsForm.visible) this.submittingSmsForm();
      if (this.formsState.clientInformationForm.visible)
        this.submittingClientInformationForm();
    }
  }
  clearIdentificationFormValues = (): void => {
    this.formsState.identificationForm.formGroup.patchValue({
      nationalId: null,
    });
  };
  //#region Databases Requested
  async verifyNationalId() {
    try {
      // Prepare the request
      const nationalId =
        this.formsState.identificationForm.formGroup.value.nationalId;
      this.DataBaseRequestsAndResponses.checkClient.request = {
        nationalId,
      };

      // Send the request and await the response
      const response = await this.cashOutService
        .checkNationId(nationalId)
        .toPromise();
      this.DataBaseRequestsAndResponses.checkClient.response = response;
      console.log(response);
      // Check the response status
      if (response.result.response_status !== 202) {
        throw new Error(response.result.message);
      }
    } catch (error) {
      throw new Error(error.message);
    }
  }
  async verifyOtp() {
    try {
      // Prepare the request
      const nationalId =
        this.formsState.identificationForm.formGroup.value.nationalId;
      const otp = this.formsState.smsForm.formGroup.value.otpInput;
      const referenceNumber =
        this.DataBaseRequestsAndResponses.checkClient.response.result.ref_no;
      this.DataBaseRequestsAndResponses.checkOtp.request = {
        nationalId,
        otp,
        referenceNumber,
      };

      // Send the request and await the response
      const response = await this.cashOutService
        .checkOtp(this.DataBaseRequestsAndResponses.checkOtp.request)
        .toPromise();
      this.DataBaseRequestsAndResponses.checkOtp.response = response;
      // Check the response status
      if (response.response_status !== 202) {
        throw new Error(response.result.message);
      }
    } catch (error) {
      throw new Error(error.message);
    }
  }
  async verifyDisburseLoan() {
    // Prepare the request
    try {
      const nationalId =
        this.formsState.identificationForm.formGroup.value.nationalId.toString();
      const referenceNumber =
        this.DataBaseRequestsAndResponses.checkClient.response.result.ref_no.toString();
      this.DataBaseRequestsAndResponses.disburseLoan.request = {
        nationalId,
        referenceNumber,
      };
      // Send the request and await the response
      const response = await this.cashOutService
        .disburseLoan(this.DataBaseRequestsAndResponses.disburseLoan.request)
        .toPromise();
      this.DataBaseRequestsAndResponses.disburseLoan.response = response;
      // Check the resopnse status
      if (response.response_status !== 202) {
        throw new Error(response.message);
      }
    } catch (error) {
      throw new Error(error.message);
    }
  }
  //#endregion
}
